public function penci_update_option() {
	check_ajax_referer( 'ajax-nonce', 'nonce' );
	$option_name = isset( $_POST['option_name'] ) ? sanitize_text_field( wp_unslash( $_POST['option_name'] ) ) : '';
	$option_val = isset( $_POST['option_val'] ) ? wp_unslash( $_POST['option_val'] ) : '';

	if ( $option_name && $option_val ) {
		update_option( $option_name, $option_val );
		wp_send_json_success( array( 'message' => 'Option updated successfully.' ) );
	} else {
		wp_send_json_error( array( 'message' => 'Invalid option name.' ) );
	}
}

public static function get_global_remediations( string $url ) : array {
    $excluded_table = Global_Remediation_Relationship_Table::table_name();
    $remediation_table = Remediation_Table::table_name();
    $global_where = [
        [
            'column' => "$remediation_table.global",
            'value' => 1,
            'operator' => '=',
        ],
    ];
    $join = "LEFT JOIN $excluded_table ON $remediation_table.id = $excluded_table.remediation_id AND $excluded_table.page_url = '$url'";
    return Remediation_Table::select(
        "$remediation_table.*, COALESCE($excluded_table.active, $remediation_table.active) AS active_for_page",
        $global_where,
        null,
        null,
        $join
    );
}

