    } else {
        $ip = $_SERVER['REMOTE_ADDR'];
    }
    return $ip; // Raw user input, no sanitization
}

// File: class-wp-members-user.php – register_finalize()
$ip = rktgk_get_user_ip();
update_user_meta( $user_id, 'wpmem_reg_ip', $ip ); // Stored in DB without sanitization

// File: class-wp-members-user-profile.php – _show_ip()
// Output when admin edits user profile:
