corrected_code:
// Fix: sanitize IP on input AND escape on output
function rktgk_get_user_ip() {
    $ip = $_SERVER['REMOTE_ADDR'];
    if ( ! empty( $_SERVER['HTTP_X_FORWARDED_FOR'] ) ) {
        $forwarded = sanitize_text_field( $_SERVER['HTTP_X_FORWARDED_FOR'] );
        // Take only first IP if comma-separated list
        $ips = explode( ',', $forwarded );
        $ip = trim( $ips[0] );
    }
    return filter_var( $ip, FILTER_VALIDATE_IP ) ? $ip : $_SERVER['REMOTE_ADDR'];
}
// On output:
echo '<td>' . esc_html( get_user_meta( $user_id, 'wpmem_reg_ip', true ) ) . '</td>';

