// CVE-2024-2030 – Database for Contact Form 7 plugin (<= 1.3.3), 60,000+ installs
// File: contact-form-entries/includes/class-vxcf-form.php, entries_shortcode()
// Step 1: esc_attr() is applied to the raw attribute value, building a string
//         that INCLUDES the surrounding quote characters:
$table_id = 'id="' . esc_attr($atts['font-size']) . '"';
// Step 2: esc_html() is then applied to the full string, escaping the quotes
//         that were already baked in, stripping the enclosing delimiters:
// In template:
<table <?php echo $class.' '.$css ?> cellspacing="0" <?php echo esc_html($table_id) ?>>

// After esc_html(), the output becomes:
//   <table id=&quot;value onmouseover=alert(/XSS/) data-more=&quot;&quot; ...>
// The browser sees: id= (no quotes), then a space → starts new attribute
// Payload: $atts['font-size'] = 'value onmouseover=alert(/XSS/) data-more='
// Result: <table id=""value" onmouseover="alert(/XSS/)" data-more="""></table>

// CVE-2023-47777 – WooCommerce Blocks <= 11.1.1 / WooCommerce < 8.2.0
// File: AbstractProductGrid render_image()
private function render_image( $attributes, $item, string $image_url ) {
    $style = sprintf( 'object-fit: %s;', $attributes['imageFit'] ); // Unescaped
    if ( $this->hasFocalPoint( $attributes ) ) {
        $style .= sprintf(
            'object-position: %s%% %s%%;',
            $attributes['focalPoint']['x'] * 100,
            $attributes['focalPoint']['y'] * 100
        );
    }
    if ( ! empty( $image_url ) ) {
        return sprintf(
            '<img alt="%1$s" class="wc-block-%2$s__background-image" src="%3$s" style="%4$s" />',
            wp_kses_post( $attributes['alt'] ?: $this->get_item_title( $item ) ), // WRONG: wp_kses_post does not escape quotes in attributes
            $this->block_name,
            $image_url,
            $style // WRONG: style string not escaped
        );
    }
    return '';
}

