// CVE in LeadConnector WordPress Plugin <= 1.7
// REST route registered with __return_true — publicly accessible to ALL users
register_rest_route('lc_public_api/v1', 'proxy', array(
    'methods'             => WP_REST_Server::CREATABLE,
    'callback'            => array($this, 'lc_public_api_proxy'),
    'permission_callback' => '__return_true', // Anyone can call this endpoint
));

// The proxy callback handles multiple actions including wp_delete_post
// WITHOUT any capability check:
public function lc_public_api_proxy( $request ) {
    $params   = $request->get_params();
    $endpoint = $params['endpoint'];
    if ($endpoint == 'wp_delete_post') {
        $body        = json_decode($params['data']);
        $post_id     = $body->post_id;
        $force_delete = $body->force_delete;
        $post_info   = wp_delete_post($post_id, $force_delete); // No auth check!
        return $post_info;
    }
    // ... more actions handled without auth
}

// Admin and Customer Messages After Order (OrderConvo) <= 1.4
// REST API route with a conditional permission_callback that returns true when no nonce is provided
register_rest_route( 'orderconvo/v1', 'send-message', array(
    'methods'             => 'POST',
    'callback'            => 'orderconvo_send_message',
    'permission_callback' => function( $request ) {
        $nonce = $request->get_header( 'X-WP-Nonce' );
        // Returns true (allows access) when nonce is NOT provided!
        if ( empty( $nonce ) ) {
            return true;
        }
        return wp_verify_nonce( $nonce, 'wp_rest' );
    },
));
// Result: unauthenticated attacker sends POST without X-WP-Nonce header
// permission_callback returns true, attacker can impersonate any user in order messages

