// Anti-pattern 1: Dynamic transient keys — causes unbounded table growth
foreach ( $product_ids as $product_id ) {
    $cache_key = 'product_price_' . $product_id; // Unique key per product
    $price = get_transient( $cache_key );
    if ( false === $price ) {
        $price = calculate_price( $product_id );
        set_transient( $cache_key, $price, HOUR_IN_SECONDS );
    }
    // On a site with 10,000 products: 10,000 rows in wp_options
    // Each with autoload=yes until WP 4.4+
}

// Anti-pattern 2: Transient with no expiration — never automatically cleaned up
set_transient( 'my_plugin_job_status', 'running' ); // No 3rd param = never expires!
// Developer expects WP cron to clean this up — it will NOT

// Anti-pattern 3: Using transients for plugin state instead of options
set_transient( 'my_plugin_version', '1.2', 0 ); // Should use update_option()
// Can be evicted at any time if persistent object cache flushes

// Anti-pattern: Plugin storing data per-request as transients, flooding wp_options
// Real case: 'Flare' social sharing plugin
// Generated entries named '_transient_flare_[page_id]' for every page visited
// With no expiration or cleanup logic
// SELECT COUNT(*) FROM wp_options WHERE option_name LIKE '_transient_flare%';
// → 353,611 rows (1 Gigabyte) on one blog
// This fills the InnoDB buffer pool, causing every MySQL query to be slower

// Also: plugin using unique transient keys per user session
function save_user_data_transient( $user_id, $data ) {
    set_transient( 'user_data_' . $user_id . '_' . time(), $data, DAY_IN_SECONDS );
    // Per-user + timestamp = unbounded unique keys = permanent table bloat
}

corrected_code:
// Fix: Use a single group-based transient with a stable key
function save_user_data_transient( $user_id, $data ) {
    set_transient( 'user_data_' . $user_id, $data, DAY_IN_SECONDS ); // Stable key overwritten on update
}

// For per-page data: use object cache instead of transients if persistence not needed
$data = wp_cache_get( 'flare_data_' . get_the_ID(), 'flare' );
if ( false === $data ) {
    $data = fetch_flare_data( get_the_ID() );
    wp_cache_set( 'flare_data_' . get_the_ID(), $data, 'flare', HOUR_IN_SECONDS );
}

// Cleanup expired transients SQL:
DELETE a, b FROM wp_options a, wp_options b
WHERE a.option_name LIKE '_transient_%'
AND a.option_name NOT LIKE '_transient_timeout_%'
AND b.option_name = CONCAT( '_transient_timeout_', SUBSTRING( a.option_name, 12 ) )
AND b.option_value < UNIX_TIMESTAMP();

