/* WordPress Navigation block — submenu-expanding button:
   No visible focus indicator by default when navigating with keyboard.
   WCAG 2.4.11 (AA, 2.2) requires a visible focus indicator.
   The theme-specific CSS outline was removed; the block renders: */

/* nav-link-container-submenu.css — applied outline was removed in certain configurations */
.wp-block-navigation .wp-block-navigation-item__content:focus {
    /* No outline rule present — keyboard focus not visible */
}

/* The submenu toggle button: */
<button class="wp-block-navigation-submenu__toggle" aria-expanded="false">
    <span class="wp-block-navigation-submenu__toggle-icon">
        <svg ...>...</svg>
    </span>
</button>
/* No outline on :focus, only a 2px solid on :focus-visible which relies on browser heuristics
   A user who clicks the button to open submenu then tabs: outline disappears (browser treats as mouse click)
   Users who activated via keyboard but UA marks as mouse interaction: no focus visible */

corrected_code:
/* Proposed fix: use :focus-visible for keyboard-only outline but ensure it's always visible when AT is active */
.wp-block-navigation .wp-block-navigation-submenu__toggle:focus-visible {
    outline: 2px solid currentColor;
    outline-offset: 2px;
}
/* And ensure theme.json defines focus-visible styles that pass WCAG 2.4.11:
   Minimum area: bounding box perimeter × 2px CSS pixels */

