// functions.php — WRONG: dependency handle uses capital 'J' → 'jQuery'
add_action('wp_enqueue_scripts', 'br_enqueue');
function br_enqueue() {
    wp_enqueue_script(
        'br-script',
        get_stylesheet_directory_uri() . '/br-tagging.js',
        array('jQuery')  // ← wrong: WordPress registered it as 'jquery' (lowercase)
    );
}

// br-tagging.js — WRONG: uses bare $ in global scope
$(window).load(function() {
    $('#br-button').click(function() {
        alert('Hello World');
    });
});
// Result: $ is not defined — WordPress loads jQuery in no-conflict mode,
// so the $ alias is deliberately removed from the global scope.

// Child theme functions.php — WRONG: registers external jQuery instead of using WordPress bundled jQuery
function child_theme_enqueue() {
    // Registers external CDN jQuery — conflicts with parent theme's bundled WordPress jQuery
    wp_enqueue_script('jquery-js', '//ajax.googleapis.com/ajax/libs/jquery/3.3.1/jquery.min.js');
    // This loads jQuery twice: CDN version + WordPress built-in jQuery
    // Also, WordPress jQuery runs in no-conflict mode, so $ is undefined
    // If parent theme uses jQuery loaded as WP built-in, two versions now conflict
}
add_action('wp_enqueue_scripts', 'child_theme_enqueue');

// Developer's second (incorrect) attempt: depends on 'jquery' but scripts run in wrong order
wp_enqueue_script('main-js', get_theme_file_uri('/js/scripts-bundled.js'), array('jquery'), '1.2', true);
// ERROR: parent theme scripts load AFTER child theme scripts (child theme enqueues first)
// scripts-bundled.js uses $ but gets loaded before parent jQuery — '$ is not a function'

corrected_code:
// Fix: Never enqueue external jQuery — use WordPress built-in via dependency handle
add_action('wp_enqueue_scripts', 'child_theme_enqueue');
function child_theme_enqueue() {
    // Use the built-in 'jquery' handle as dependency — WP resolves load order
    wp_enqueue_script(
        'main-js',
        get_stylesheet_directory_uri() . '/js/scripts-bundled.js',
        array('jquery'), // WP ensures jQuery is loaded first
        '1.2',
        true
    );
}
// Also wrap all jQuery code in no-conflict wrapper:
// (function($) { /* your code using $ here */ })(jQuery);

