// Anti-pattern 1: Flushing rewrite rules on every request inside init hook
function my_plugin_init() {
    register_post_type( 'my_cpt', array( /* ... */ ) );
    flush_rewrite_rules(); // WRONG: extremely expensive, runs on every request
}
add_action( 'init', 'my_plugin_init' );

// Anti-pattern 2: Enqueueing scripts inside init instead of wp_enqueue_scripts
function my_plugin_init_scripts() {
    wp_enqueue_script( 'my-script', plugin_dir_url(__FILE__) . 'script.js', array('jquery') );
    // WRONG: runs on EVERY request (frontend AND backend), not just when needed
    // wp_enqueue_scripts hook does NOT fire on admin pages — but init does
}
add_action( 'init', 'my_plugin_init_scripts' );

// Anti-pattern 3: Adding menu pages inside admin_init instead of admin_menu
function my_plugin_admin_init_menu() {
    add_menu_page( 'My Plugin', 'My Plugin', 'manage_options', 'my-plugin', 'my_callback' );
    // WRONG: admin_init fires after admin_menu; menu registration here is unreliable
}
add_action( 'admin_init', 'my_plugin_admin_init_menu' );

corrected_code:
// Fix 1: Flush rewrite rules only on plugin activation — never on every request
register_activation_hook( __FILE__, function() {
    register_post_type( 'my_cpt', array( /* ... */ ) );
    flush_rewrite_rules(); // Only runs once, when plugin is activated
});
// On every request, just register the CPT:
add_action( 'init', function() {
    register_post_type( 'my_cpt', array( /* ... */ ) );
});

// Fix 2: Use the correct hook for script enqueueing
add_action( 'wp_enqueue_scripts', function() {
    wp_enqueue_script( 'my-script', plugin_dir_url(__FILE__) . 'script.js', array('jquery') );
    // Only fires on frontend, not admin pages
});

// Fix 3: Use admin_menu for menu pages
add_action( 'admin_menu', function() {
    add_menu_page( 'My Plugin', 'My Plugin', 'manage_options', 'my-plugin', 'my_callback' );
});

