// violating the WordPress.org plugin directory requirement.
// Example of the defective pattern:
function activate_plugin() { ... }  // too generic, no prefix
function deactivate_plugin() { ... } // too generic, no prefix
class Admin { ... } // class name too short, collides with any plugin defining 'Admin'
$my_option = get_option( 'settings' ); // option key has no prefix, may collide in wp_options

// WordPress Core uses is_integer() (an alias) inconsistently alongside is_int() (the canonical name):
if ( is_integer( $value ) ) { ... }  // uses deprecated alias
if ( is_long( $count ) ) { ... }     // uses another deprecated alias
if ( is_double( $ratio ) ) { ... }  // uses deprecated alias for is_float()

// Gutenberg PHP files use documentation/formatting that diverges from WordPress Core's PHPCS ruleset:
// 1. Missing docblocks:
function gutenberg_get_block_file_template( $template_file, $template_type ) {
    // no /** @param ... @return */ docblock
    return $template;
}

// 2. Incorrect comment format (single-line instead of docblock for hooks):
// Hook: gutenberg_pre_get_block_file_template
$result = apply_filters( 'gutenberg_pre_get_block_file_template', null, $template_file, $template_type );

// 3. Incorrect class/function naming (camelCase instead of snake_case):
function gutenbergGetBlockTemplate() { ... } // wrong for PHP in WP context

// __experimentalGetAllowedPatterns merges block patterns + reusable blocks into one selector,
// with memoization keyed on rootClientId. When the user selects a block from a different
// parent, the entire selector (including ALL pattern parsing) re-runs:
export const __experimentalGetAllowedPatterns = createRegistrySelector(
    ( select ) => createSelector(
        ( state, rootClientId = null ) => {
            const availableParsedPatterns = getAllParsedPatterns( state );
            const patternsAllowed = availableParsedPatterns.filter(
                ( { blocks } ) =>
                    blocks.every( ( { name } ) =>
                        canInsertBlockType( state, name, rootClientId )
                    )
            );
            return patternsAllowed;
        },
        ( state, rootClientId ) => [
            ...getAllowedPatternsDependants( select )( state, rootClientId ),
        ]
    )
);

corrected_code:
// Proposed fix: split loading (expensive, infrequent) from filtering (cheap, frequent)
// so that selecting a different block doesn't invalidate the full pattern parse cache.
// Either:
// (a) Separate selectors for block patterns vs. reusable blocks (user patterns)
// (b) Use server-side search and pagination instead of fetching and filtering client-side

code:
/* WordPress admin — link hover state is communicated
   solely by a color change from #0073aa (rest) to #00a0d2 (hover).
   The hover color has insufficient contrast against the
   most common admin backgrounds, and no non-color cue
   (underline, border, icon) is added on hover. */

a {
  color: #0073aa;
}
a:hover,
a:active {
  color: #00a0d2; /* contrast ratios:
    3.02:1 on white #ffffff   (WCAG AA requires 4.5:1)
    2.67:1 on grey  #f1f1f1   (admin default bg)
    2.87:1 on grey  #f9f9f9   (table zebra stripe)
    — all below WCAG 1.4.3 minimum AND
    no text-decoration or other non-color cue is added */
  color: #00a0d2;
}

corrected_code:
/* Fix committed in WordPress 5.3.1:
   hover color changed to #006799, which achieves
   ≥4.5:1 contrast on all admin backgrounds. */
a:hover,
a:active {
  color: #006799;
}

/* The ticket also proposed non-color alternatives
   that were not committed but remain best practice: */
a:hover {
  color: #006799;
  text-decoration: underline; /* adds non-color hover cue */
}

code:
/* The Lightbox implementation branches focus behavior
   based on event.pointerType, which is unreliable across browsers: */

function openLightbox( event ) {
  // Intended: skip focus transfer for pointer/touch interactions,
  // apply only for keyboard. But:
  // Chrome/Opera: event.pointerType === '' on keyboard (expected)
  // Firefox/Safari: event.pointerType === undefined on keyboard
  // This condition therefore evaluates differently per browser.
  if ( event.pointerType !== '' ) {
    // Pointer/touch path: focus is NOT moved to the dialog.
    // Focus stays on the page behind the dialog:
    //   - tabbing navigates page content behind the modal
    //   - dialog is not announced by screen readers
    //   - Escape key does not close the dialog
    return;
  }
  // Keyboard path (only reached in Chrome, not Firefox/Safari):
  dialog.querySelector( '.close-button' ).focus();
}

function closeLightbox() {
  // Focus is not returned to the trigger button.
  // Result: complete focus loss — next Tab press
  // restarts from the document root.
  dialog.close();
}

