code:
/* number_format_i18n() before fix — delegates directly to PHP number_format() */
function number_format_i18n( $number, $decimals = 0 ) {
    global $wp_locale;
    if ( isset( $wp_locale ) ) {
        $formatted = number_format(
            $number,
            absint( $decimals ),
            $wp_locale->number_format['decimal_point'],
            $wp_locale->number_format['thousands_sep']
        );
    } else {
        $formatted = number_format( $number, absint( $decimals ) );
    }
    return $formatted;
}
/* Concrete failure: Czech/Russian locale sets thousands_sep = '\xA0' (non-breaking space, Windows-1252).
   number_format( 1000, 0, ',', "\xA0" ) returns '1?000' — corrupted output. */
echo number_format( 1000, 0, ',', "\xA0" ); // => '1�000' on PHP <= 5.3

/* Common plugin/theme anti-pattern: hardcoded English date format string, bypassing locale */
echo date_i18n( 'F j, Y', get_the_date( 'U' ) );
// Produces 'April 7, 2026' in every locale;
// German translator expects '7. April 2026', Japanese expects '2026年4月7日'.

/* Even with date_i18n, passing a hardcoded format ignores the translator-adjustable format:
   'Note that the format, however, is not converted to a local one if you manually specify it.' */

