/* WordPress core approach (class-wp-posts-list-table.php): wrap format string in __() */
$t_time = sprintf(
    /* translators: 1: Post date, 2: Post time. */
    __( '%1$s at %2$s' ),
    /* translators: Post date format. See https://www.php.net/manual/datetime.format.php */
    get_the_time( __( 'Y/m/d' ), $post ),
    /* translators: Post time format. See https://www.php.net/manual/datetime.format.php */
    get_the_time( __( 'g:i a' ), $post )
);
/* This allows locale teams to translate 'Y/m/d' → 'd.m.Y' (German) or 'Y年m月d日' (Japanese). */

code:
// Plugin enqueues a script or script module with an unregistered dependency handle.
// Before WP 6.9.1 there was NO notice — WordPress silently skipped printing the asset.
add_action(
    'wp_enqueue_scripts',
    static function () {
        // Classic script: silently not printed if 'classic-dependency' handle is absent
        wp_enqueue_script(
            'classic-script-with-missing-dependency',
            'https://example.com/classic-script.js',
            array( 'classic-dependency' )  // handle not registered
        );
        // Script module (WP 6.8): was PRINTED despite missing dependency — changed in 6.9
        wp_enqueue_script_module(
            'script-module-with-missing-dependency',
            'https://example.com/script-module.js',
            array( 'module-dependency' )  // handle not registered
        );
    }
);
// Version matrix:
//   WP 6.8 classic scripts: NOT printed, no notice
//   WP 6.8 script modules:  PRINTED (missing dep ignored), no notice
//   WP 6.9 script modules:  NOT printed (r60999 fix for #63486), no notice
//   WP 6.9.1+: _doing_it_wrong() notice added for both

// Plugin registers a script intending it to load in the <head> (in_footer=false),
// but uses the new WP 6.3 array syntax for $args without a version guard:
wp_register_script(
    'foo',
    '/path/to/foo.js',
    array(),
    '1.0.0',
    array(
        'strategy' => 'defer',
        'in_footer' => false,  // intends: print in <head>
    )
);
// On WP < 6.3: the array() passed as $in_footer evaluates to boolean true.
// Result: script silently loads in the footer — no error, no warning.
// wp_register_script signature before 6.3: ..., $in_footer = false
// array() cast to bool = true => loads in footer, opposite of intent.

corrected_code:
// Option 1: version-guarded wrapper
function myplugin_register_script( $handle, $src, $deps, $ver, $args ) {
    global $wp_version;
    if ( version_compare( $wp_version, '6.3', '>=' ) ) {
        wp_register_script( $handle, $src, $deps, $ver, $args );
    } else {
        $in_footer = isset( $args['in_footer'] ) ? $args['in_footer'] : false;
        wp_register_script( $handle, $src, $deps, $ver, $in_footer );
    }
}

// Option 2: use wp_script_add_data() for strategy only (backward-safe)
wp_register_script( 'foo', '/path/to/foo.js', array(), '1.0.0', false );
wp_script_add_data( 'foo', 'strategy', 'defer' );
// wp_script_add_data is understood by WP 6.3+ and silently ignored on older versions.

code:
// Before WP 6.4 fix (r56522):
// set_transient() called without an expiration argument.
// WordPress rule: transients WITHOUT expiration are stored in wp_options with autoload=yes.
// This caused dirsize_cache to be autoloaded on EVERY page request.

// In wp-includes/functions.php, recurse_dirsize():
set_transient( 'dirsize_cache', $dirsize_cache ); // No $expiration argument
// ^ Result: wp_options row: option_name='_transient_dirsize_cache', autoload='yes'
// This transient grows proportionally to the number of subdirectories under wp-content/uploads.
// On a site with 207,221 upload subfolders: 20 MB loaded on every page via:
//   SELECT option_name, option_value FROM wp_options WHERE autoload = 'yes'
// Query takes 1s+ on 32 GB RAM / 8 CPU database servers.
// Usage context: only needed on Dashboard, Site Health, and multisite quota pages.
// 99% of requests load 20MB they never use.

// In wp-includes/media.php (since WP 5.5, the bug):
// wp_filter_content_tags() hooked to the_content at priority 10 (default).
add_filter( 'the_content', 'wp_filter_content_tags', 10 );

// In wp-includes/shortcodes.php:
// do_shortcode() hooked to the_content at priority 11.
add_filter( 'the_content', 'do_shortcode', 11 );

// Execution order: wp_filter_content_tags() runs FIRST (priority 10),
// then do_shortcode() expands shortcodes (priority 11).
//
// Defect: wp_filter_content_tags() processes HTML content for image optimizations
// (loading=lazy, fetchpriority=high) BEFORE shortcodes are expanded.
// Images inside shortcodes are invisible to wp_filter_content_tags() at priority 10.
// After shortcode expansion at priority 11, those images are never re-processed.
//
// Boundary case — the wrong image gets fetchpriority=high:
// If the post contains:
//   [shortcode]  <- generates a large above-the-fold image
//   <img>        <- a regular block image below the fold
//
// wp_filter_content_tags (priority 10) sees only the <img> tag (shortcode not yet expanded).
// It assigns fetchpriority="high" to the <img> (first image it sees).
// do_shortcode (priority 11) then expands the shortcode, generating the large image.
// The shortcode image gets loading="lazy" from the separate do_shortcode context,
// even though it is above the fold and should have fetchpriority="high".
// The wrong image is prioritized for LCP; the LCP image is lazily loaded.

corrected_code:
// Fix committed in r56693 (WP 6.3), authored by flixos90:
// Change wp_filter_content_tags() priority to 12 (after do_shortcode at 11).
remove_filter( 'the_content', 'wp_filter_content_tags', 10 );
add_filter( 'the_content', 'wp_filter_content_tags', 12 );
// Same change applied to widget_text_content and widget_block_content filters.

// Also: add do_shortcode context to early-return guard in
// wp_get_loading_optimization_attributes() so shortcode-generated images
// are processed within their parent content blob rather than in isolation:
// (prevent double-counting images seen during nested shortcode processing)

