// WP Rocket compatibility file (correct for pages WITHOUT CF7 forms):
add_filter( 'wpcf7_load_js', '__return_false' );   // Prevents CF7 JS loading
add_filter( 'wpcf7_load_css', '__return_false' );  // Prevents CF7 CSS loading

// CF7 (v5.8.6) script registration pattern:
// controller.php#L49-L58: registers 'contact-form-7' handle WITHOUT enqueuing it
// controller.php#L110:    enqueues it only when wpcf7_load_js filter returns true
// controller.php#L68-L70: applies wpcf7_load_js filter to decide whether to enqueue

// Conditional Fields for CF7 (v2.4.6) — the third-party trigger:
// cf7cf.php#L510: enqueues its own scripts
// cf7cf.php#L524: enqueues with 'contact-form-7' as a hard dependency:
wp_enqueue_script(
    'cf7cf-script',
    plugin_dir_url( __FILE__ ) . 'js/cf7cf.js',
    array( 'contact-form-7', 'jquery' ),  // Forces CF7 script enqueue via WP dependency system
    CF7CF_VERSION,
    true
);
// OR a custom theme:
add_action( 'wp_enqueue_scripts', 'theme_scripts', 100 );
function theme_scripts() {
    wp_enqueue_script(
        'theme-contact-form-7-ext',
        get_stylesheet_directory_uri() . '/assets/js/contact-form-7.js',
        array( 'contact-form-7', 'jquery' ),  // Hard dependency on CF7 handle
        THEME_VERSION,
        array( 'in_footer' => true )
    );
}

// Result on pages WITHOUT CF7 forms, when WP Rocket is active:
// 1. WP Rocket sets wpcf7_load_js -> false (correct intent: don't load CF7)
// 2. CF7 script is REGISTERED (as a handle) but not enqueued by CF7 itself
// 3. Third-party's wp_enqueue_script with 'contact-form-7' in $deps forces
//    WP dependency resolver to enqueue the 'contact-form-7' handle
// 4. CF7 script loads, but WITHOUT the wp_localize_script('wpcf7') call
//    (that call only happens inside CF7's own enqueue function, gated by wpcf7_load_js)
// 5. CF7's JavaScript references window.wpcf7 which does not exist -> console errors
//    Datepicker, conditional logic, form validation all break silently

add_action('wp_ajax_update_settings', function() {
    if (!current_user_can('manage_options')) { exit; }

    // Non-Yoda: condition reads 'if action is set AND nonce fails'
    if (isset($_POST['action']) && !wp_verify_nonce('action', 'action')) {
        exit;
    }

    update_option('my_settings', ['setting1' => esc_html($_POST['setting1'])]);
});

corrected_code:
add_action('wp_ajax_update_settings', function() {
    if (!current_user_can('manage_options')) { exit; }

    if (!isset($_POST['action']) || !wp_verify_nonce('action', 'action')) {
        exit;
    }

    update_option('my_settings', ['setting1' => sanitize_text_field(wp_unslash($_POST['setting1']))]);
});

code:
// Defective: esc_url_raw used for output — it is a sanitization function, not an escaping function
echo '<a href="' . esc_url_raw($url) . '">Click</a>';

// Also defective: using a sanitize function (sanitize_text_field) in place of esc_html at echo point
echo sanitize_text_field($_POST['example']);

// Defective: using filter_input without a sanitizing filter
$post_id = filter_input(INPUT_GET, 'post_id'); // applies FILTER_DEFAULT — not sanitizing

corrected_code:
// Correct: esc_url for output
echo '<a href="' . esc_url($url) . '">Click</a>';

// Correct: sanitize on input, escape on output
echo esc_html(sanitize_text_field($_POST['example']));

// Correct: provide a sanitizing filter constant
$post_id = filter_input(INPUT_GET, 'post_id', FILTER_SANITIZE_NUMBER_INT);

