$variable = $_REQUEST['id'];

// Wrong: sanitize_text_field does not remove quotes or escape values for SQL
$wpdb->get_var("SELECT * FROM wp_users WHERE id = " . sanitize_text_field($variable));

// Also wrong: esc_sql escapes but the value must be in quotes in the query
$wpdb->get_var("SELECT * FROM wp_users WHERE id = " . esc_sql($variable));

// Incomplete fix: sanitize_text_field applied on input, but _e() used for HTML-attribute output
// $cltranslate was sanitized upstream with sanitize_text_field(), creating false safety
<div class="af2_post_table_content"
     data-searchvalue="<?php _e($cltranslate); ?>">

// Early escaping creates false safety: $url and $text appear "safe" but
// something could inadvertently change the variable before it is output
$url  = esc_url( $url );
$text = esc_html( $text );

// ... potentially many lines of code ...
// Another developer may later add: $url .= $_GET['extra']; // re-taints the escaped variable

echo '<a href="' . $url . '">' . $text . '</a>';

// Escaping applied at point of passing to wp_verify_nonce — creates false safety:
// esc_html alters the nonce token, causing legitimate nonces to FAIL verification
wp_verify_nonce( esc_html( get_request_nonce() ), 'my-action' );

// Demonstrated by sybrew with a nonce containing '<':
// get_request_nonce() returns 'some<-hash'
// esc_html converts it to 'some&lt;-hash'
// wp_verify_nonce('some&lt;-hash') returns 0 (false negative) instead of 1

corrected_code:
// For distributed plugins: sanitize_text_field + wp_unslash
wp_verify_nonce( sanitize_text_field( wp_unslash( $_POST['my-nonce'] ) ), 'my-action' );

// For non-distributed code where nonce format is known:
wp_verify_nonce( sanitize_key( $_POST['my-nonce'] ), 'my-action' );

// Most correct per WPCS sniff suppression (raw, no sanitization needed):
if ( ! isset( $_POST['my-nonce'] ) || ! wp_verify_nonce( wp_unslash( $_POST['my-nonce'] ), 'my-action' ) ) {
    wp_die();
}

